@st.cache_data
def _load_bg_image():
    from PIL import Image
    import io, base64
    img_data = base64.b64decode(PDF_BG_IMAGE)
    return Image.open(io.BytesIO(img_data)).convert("RGB")

@st.cache_data(show_spinner=False)
def generate_island_image(diff_map_tuple, machine_map_tuple=(), date_key="", as_pdf=False):
    """PILで高速に差枚+機種名オーバーレイ画像を生成（キャッシュ付き）"""
    from PIL import Image, ImageDraw, ImageFont
    import io

    diff_map = dict(diff_map_tuple)
    machine_map = dict(machine_map_tuple)

    # 背景をコピー
    bg = _load_bg_image().copy()
    W, H = bg.size
    draw = ImageDraw.Draw(bg)

    # フォント（日本語対応 - 複数パスを試行）
    FONT_SIZE = 17
    FONT_SM = 13
    JP_FONT_PATHS = [
        "/usr/share/fonts/opentype/ipafont-gothic/ipag.ttf",
        "/usr/share/fonts/opentype/ipaexfont-gothic/ipaexg.ttf",
        "/usr/share/fonts/truetype/fonts-japanese-gothic.ttf",
        "/usr/share/fonts/opentype/noto/NotoSansCJK-Bold.ttc",
        "/usr/share/fonts/opentype/noto/NotoSansCJK-Regular.ttc",
        "fonts/ipag.ttf",  # リポジトリ同梱用
    ]
    font = None
    font_sm = None
    for fp in JP_FONT_PATHS:
        try:
            import os
            if not os.path.exists(fp): continue
            kw = {"index": 0} if fp.endswith(".ttc") else {}
            font    = ImageFont.truetype(fp, FONT_SIZE, **kw)
            font_sm = ImageFont.truetype(fp, FONT_SM,   **kw)
            break
        except: continue
    if font is None:
        font    = ImageFont.load_default()
        font_sm = font

    def get_color(diff):
        if diff >= 10000: return (17, 17, 17)
        if diff >= 5000:  return (139, 0, 0)
        if diff >= 4000:  return (204, 0, 0)
        if diff >= 3000:  return (180, 50, 180)
        if diff >= 2000:  return (80, 160, 60)
        if diff >= 1000:  return (180, 180, 0)
        if diff > 0:      return (100, 180, 220)
        if diff == 0:     return (200, 200, 200)
        return (255, 255, 255)  # マイナスは白背景

    def get_text_color(diff):
        if diff < 0: return (220, 0, 0)
        if diff >= 1000: return (255, 255, 255)
        return (40, 40, 40)

    def get_outline_color(diff):
        if diff < 0: return (220, 0, 0)
        return (200, 200, 200)

    BW = 56
    BH = 20

    for num, (rx, ry) in PDF_POSITIONS.items():
        diff = diff_map.get(num)
        if diff is None or (isinstance(diff, float) and np.isnan(diff)):
            continue
        diff = float(diff)

        # PDF_POSITIONSの座標をそのまま使用
        px = int(rx * W)
        py = int(ry * H)

        color = get_color(diff)
        outline_c = get_outline_color(diff)

        # 差枚バッジ（台番の上にずらして台番が見えるように）
        SHIFT = 18  # 上にずらすピクセル数
        x0, y0 = px - BW//2, py - BH//2 - SHIFT
        x1, y1 = px + BW//2, py + BH//2 - SHIFT
        draw.rectangle([x0, y0, x1, y1], fill=color)
        draw.rectangle([x0, y0, x1, y1], outline=outline_c, width=1)

        text = f"+{int(diff):,}" if diff > 0 else ("0" if diff == 0 else f"{int(diff):,}")
        text_color = get_text_color(diff)
        try:
            bbox = draw.textbbox((0, 0), text, font=font)
            tw = bbox[2] - bbox[0]
            th = bbox[3] - bbox[1]
        except:
            tw, th = len(text) * 9, FONT_SIZE
        draw.text((px - tw//2, py - th//2 - SHIFT), text, fill=text_color, font=font)

        # 機種名（バッジの下）
        machine = machine_map.get(num, "")
        if machine:
            short = shorten_name(machine)
            try:
                mbbox = draw.textbbox((0, 0), short, font=font_sm)
                mw = mbbox[2] - mbbox[0]
                mh = mbbox[3] - mbbox[1]
            except:
                mw, mh = len(short) * 7, FONT_SM
            mx0 = px - mw//2 - 1
            my0 = py + BH//2 + 2
            mx1 = px + mw//2 + 1
            my1 = my0 + mh + 2
            draw.rectangle([mx0, my0, mx1, my1], fill=(255, 255, 255))
            draw.text((px - mw//2, my0 + 1), short, fill=(50, 50, 50), font=font_sm)

    buf = io.BytesIO()
    bg_rgb = bg.convert("RGB")
    if as_pdf:
        bg_rgb.save(buf, format="PDF", resolution=200)
    else:
        bg_rgb.save(buf, format="PNG", optimize=True)
    return buf.getvalue()


def process_df(df_raw):
    df = pd.DataFrame()
    cols = {c.strip(): c for c in df_raw.columns}
    def fc(*keys):
        for k in keys:
            for c in cols:
                if k in c: return cols[c]
        return None
    台番col = fc("台番", "台no", "No")
    機種col = fc("機種名", "機種", "name")
    差枚col = fc("差枚", "前日差枚")
    回転col = fc("回転数", "回転", "G数")
    ボーナスcol = fc("ボーナス", "bonus")
    if not 台番col or not 機種col: return None
    df["台番"] = df_raw[台番col].apply(parse_num)
    df["機種名"] = df_raw[機種col].astype(str).str.strip()
    df["前日差枚"] = df_raw[差枚col].apply(parse_num) if 差枚col else np.nan
    df["回転数"] = df_raw[回転col].apply(parse_num) if 回転col else np.nan
    df["ボーナス"] = df_raw[ボーナスcol].apply(parse_num) if ボーナスcol else np.nan
    df["週平均"] = df["前日差枚"]
    df["is_juggler"] = df["機種名"].apply(is_juggler)
    df.index = range(len(df))
    return df

@st.cache_data(ttl=300)
def load_today():
    try:
        client = get_gspread_client()
        sp = client.open_by_key(SPREADSHEET_ID)
        sheets = sorted(
            [ws for ws in sp.worksheets() if re.match(r"\d{4}-\d{2}-\d{2}", ws.title)],
            key=lambda ws: ws.title, reverse=True
        )
        if not sheets: return None, None
        ws = sheets[0]
        data = ws.get_all_records()
        if not data: return None, None
        df = pd.DataFrame(data)
        result = process_df(df)
        if result is None: return None, None
        return result, ws.title
    except Exception as e:
        st.error(f"データ読み込みエラー: {e}")
        return None, None

def load_history(max_days=10):
    try:
        client = get_gspread_client()
        spreadsheet = client.open_by_key(SPREADSHEET_ID)
        all_ws = spreadsheet.worksheets()
        date_sheets = [ws for ws in all_ws if re.match(r"\d{4}-\d{2}-\d{2}", ws.title)]
        date_sheets = sorted(date_sheets, key=lambda w: w.title, reverse=True)[:max_days]
        history = {}
        date_labels = [ws.title for ws in date_sheets]
        for ws in date_sheets:
            try:
                data = ws.get_all_records()
                if not data: continue
                df = pd.DataFrame(data)
                cols = {c.strip(): c for c in df.columns}
                def fc(*keys):
                    for k in keys:
                        for c in cols:
                            if k in c: return cols[c]
                    return None
                台番col = fc("台番", "台no", "No")
                差枚col = fc("差枚", "前日差枚", "差枚数")
                回転col = fc("回転数", "回転", "G数", "ゲーム数")
                if not 台番col or not 差枚col: continue
                for _, row in df.iterrows():
                    try:
                        num = int(parse_num(row[台番col]))
                        diff = parse_num(row[差枚col])
                        rot = parse_num(row[回転col]) if 回転col else np.nan
                        if num not in history: history[num] = {}
                        history[num][ws.title] = {"diff": diff, "rot": rot}
                    except: continue
            except: continue
        return history, date_labels
    except Exception as e:
        return {}, []

