PDF_BG_IMAGE = ""
PDF_IMG_W = 2205
PDF_IMG_H = 1978


def make_pdf_island_map(df, target_machines=None, diff_override=None):
    """PDFを背景に差枚をオーバーレイした島図"""
    import plotly.graph_objects as go

    diff_map = {}
    for _, row in df.iterrows():
        if not np.isnan(row["台番"]):
            n = int(row["台番"])
            diff_map[n] = row["前日差枚"]
    if diff_override:
        for n, v in diff_override.items():
            diff_map[n] = v
    if target_machines is None:
        target_machines = set()

    fig = go.Figure()

    # 背景画像
    import base64
    fig.add_layout_image(
        dict(
            source=f"data:image/png;base64,{PDF_BG_IMAGE}",
            xref="x", yref="y",
            x=0, y=0,
            sizex=PDF_IMG_W, sizey=PDF_IMG_H,
            sizing="stretch",
            opacity=1.0,
            layer="below"
        )
    )

    shapes = []
    annotations = []
    BW = 30  # バッジ幅
    BH = 18  # バッジ高さ
    OFFSET_Y = 22  # 台番の上にずらすピクセル数

    for mno, (rx, ry) in PDF_POSITIONS.items():
        px = rx * PDF_IMG_W
        py = ry * PDF_IMG_H

        diff = diff_map.get(mno, np.nan)
        bg = diff_to_color(diff)
        text_c = diff_to_text_color(diff)
        is_target = mno in target_machines

        # データなしはスキップ
        if np.isnan(diff):
            if is_target:
                by = py - OFFSET_Y
                shapes.append(dict(
                    type="rect",
                    x0=px - BW/2 - 2, y0=by - BH/2 - 2,
                    x1=px + BW/2 + 2, y1=by + BH/2 + 2,
                    fillcolor="rgba(0,0,0,0)",
                    line=dict(color="#FFD700", width=2.5),
                    layer="above"
                ))
            continue

        by = py - OFFSET_Y  # 台番の上に配置

        border_c = "#FFD700" if is_target else ("rgba(200,0,0,0.9)" if diff <= -500 else "rgba(50,50,50,0.4)")
        border_w = 2.5 if is_target else (1.5 if diff <= -500 else 0.8)

        shapes.append(dict(
            type="rect",
            x0=px - BW/2, y0=by - BH/2,
            x1=px + BW/2, y1=by + BH/2,
            fillcolor=bg,
            opacity=0.92,
            line=dict(color=border_c, width=border_w),
            layer="above"
        ))

        if np.isnan(diff): diff_text = "?"
        elif diff > 0: diff_text = f"+{int(diff):,}"
        elif diff == 0: diff_text = "0"
        else: diff_text = f"{int(diff):,}"

        annotations.append(dict(
            x=px, y=by,
            text=f"<b>{diff_text}</b>",
            showarrow=False,
            font=dict(size=7, color=text_c),
            xanchor="center", yanchor="middle"
        ))

    fig.update_layout(
        width=PDF_IMG_W,
        height=PDF_IMG_H,
        paper_bgcolor="#0a0e1a",
        plot_bgcolor="rgba(0,0,0,0)",
        showlegend=False,
        margin=dict(l=0, r=0, t=0, b=0),
        xaxis=dict(visible=False, range=[0, PDF_IMG_W], scaleanchor="y"),
        yaxis=dict(visible=False, range=[PDF_IMG_H, 0]),  # y軸反転（PDF座標系）
        shapes=shapes,
        annotations=annotations,
    )
    return fig


